#include<bits/stdc++.h>
using namespace std;
struct node{
	int b,c,a,z,h;
}d[501];
int main()
{
	int i,j,n;
	scanf("%d",&n);
	for(i=1;i<=n;i++)
	{
		scanf("%d%d%d",&d[i].a,&d[i].b,&d[i].c);
		d[i].h=i;
		d[i].z=d[i].a+d[i].b+d[i].c;
	}
	for(i=n;i>=1;i--)
	{
		for(j=1;j<=i;j++)
		{
			if(d[j].z<d[j+1].z||d[j].z==d[j+1].z&&d[j].a<d[j+1].a)
			{
				swap(d[j],d[j+1]);
			}
		}
	}
	for(i=1;i<=5;i++)
	{
		printf("%d %d\n",d[i].h,d[i].z);
	}
	return 0;
}
